import{_ as t,a,b as o}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as d,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Přidání kanálu Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/cloudflare-r2.md","filePath":"cs-CZ/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),r={name:"cs-CZ/upload/cloudflare-r2.md"};function u(s,e,c,p,v,b){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="pridani-kanalu-cloudflare-r2" tabindex="-1">Přidání kanálu Cloudflare R2 <a class="header-anchor" href="#pridani-kanalu-cloudflare-r2" aria-label="Permalink to &quot;Přidání kanálu Cloudflare R2&quot;">​</a></h1><h2 id="kdy-se-hodi" tabindex="-1">Kdy se hodí <a class="header-anchor" href="#kdy-se-hodi" aria-label="Permalink to &quot;Kdy se hodí&quot;">​</a></h2><p>Cloudflare R2 použijte, když:</p><ul><li>vaše stránka ImgBed už běží na Cloudflare a chcete soubory ukládat do R2 bucketu ve stejném účtu Cloudflare.</li><li>nechcete nastavovat samostatný S3 endpoint, access key a secret key.</li><li>chcete, aby čtení a zápis probíhaly přes R2 binding ve Workeru nebo Pages s minimální konfigurací.</li></ul><p>Stručně:</p><p>Kanál R2 se nevytváří ručně v administraci ImgBed. Nejprve je potřeba připojit R2 bucket k projektu Cloudflare a název proměnné bindingu musí být přesně <code>img_r2</code>.</p><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><ul><li>Účet Cloudflare.</li><li>Existující R2 bucket.</li><li>Oprávnění spravovat projekt Cloudflare, na kterém je ImgBed nasazený.</li></ul><h2 id="nastaveni-v-cloudflare" tabindex="-1">Nastavení v Cloudflare <a class="header-anchor" href="#nastaveni-v-cloudflare" aria-label="Permalink to &quot;Nastavení v Cloudflare&quot;">​</a></h2><h3 id="_1-vytvorte-r2-bucket" tabindex="-1">1. Vytvořte R2 bucket <a class="header-anchor" href="#_1-vytvorte-r2-bucket" aria-label="Permalink to &quot;1. Vytvořte R2 bucket&quot;">​</a></h3><ol><li>Přihlaste se do Cloudflare Dashboard.</li><li>Otevřete <code>R2 Object Storage</code>.</li><li>Klikněte na Create bucket.</li><li>Zvolte název bucketu, například <code>imgbed</code>.</li></ol><p>Do tohoto bucketu se budou ukládat nahrané soubory.</p><p><img src="'+t+'" alt="Vytvoření R2 bucketu" loading="lazy"></p><h3 id="_2-pripojte-bucket-k-projektu-imgbed" tabindex="-1">2. Připojte bucket k projektu ImgBed <a class="header-anchor" href="#_2-pripojte-bucket-k-projektu-imgbed" aria-label="Permalink to &quot;2. Připojte bucket k projektu ImgBed&quot;">​</a></h3><p>Místo bindingu vyberte podle typu nasazení:</p><table tabindex="0"><thead><tr><th>Typ nasazení</th><th>Místo bindingu</th></tr></thead><tbody><tr><td>Pages</td><td>Aktuální Pages projekt -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Aktuální Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Při přidávání bindingu jsou důležitá tato pole:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Hodnota</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Vyberte bucket, který jste vytvořili</td></tr></tbody></table><p>Název proměnné musí být přesně <code>img_r2</code>. Nahrávání, čtení i mazání souborů R2 závisí na tomto názvu bindingu.</p><h3 id="_3-projekt-znovu-nasadte" tabindex="-1">3. Projekt znovu nasaďte <a class="header-anchor" href="#_3-projekt-znovu-nasadte" aria-label="Permalink to &quot;3. Projekt znovu nasaďte&quot;">​</a></h3><p>Po uložení bindingu znovu nasaďte ImgBed, aby runtime Workeru nebo Pages získal přístup k <code>img_r2</code>.</p><h2 id="co-uvidite-v-imgbed" tabindex="-1">Co uvidíte v ImgBed <a class="header-anchor" href="#co-uvidite-v-imgbed" aria-label="Permalink to &quot;Co uvidíte v ImgBed&quot;">​</a></h2><p>Jakmile je binding R2 dostupný, otevřete:</p><ol><li>Nastavení systému.</li><li>Nastavení nahrávání.</li><li>Kanál <code>Cloudflare R2</code>.</li></ol><p>Systém automaticky vytvoří jeden pevný kanál:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Pevná hodnota</th></tr></thead><tbody><tr><td>Název kanálu</td><td><code>Cloudflare R2</code></td></tr><tr><td>Typ kanálu</td><td><code>cfr2</code></td></tr><tr><td>Režim úložiště</td><td><code>binding</code></td></tr><tr><td>Zdroj konfigurace</td><td>Environment binding</td></tr></tbody></table><p>Jde o pevný kanál bindingu. Nemusíte ho vytvářet přes Přidat kanál a nelze ho smazat jako běžný kanál.</p><h2 id="upravitelna-pole-v-administraci" tabindex="-1">Upravitelná pole v administraci <a class="header-anchor" href="#upravitelna-pole-v-administraci" aria-label="Permalink to &quot;Upravitelná pole v administraci&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Co dělá</th><th>Povinné</th></tr></thead><tbody><tr><td>Povolit kanál</td><td>Určuje, zda se R2 účastní výběru kanálu při nahrávání.</td><td>Ano</td></tr><tr><td>Account ID</td><td>Používá se jen při zapnutých limitech kapacity, když je potřeba dotazovat oficiální využití R2.</td><td>Doporučeno při limitech</td></tr><tr><td>Název bucketu</td><td>Používá se jen při zapnutých limitech kapacity, když je potřeba dotazovat oficiální využití R2.</td><td>Doporučeno při limitech</td></tr><tr><td>Limit kapacity</td><td>Určuje, zda se tento R2 kanál vybírá podle dostupné kapacity.</td><td>Ne</td></tr><tr><td>Prahová hodnota</td><td>Zastaví zápis do kanálu po dosažení zadaného procenta využití.</td><td>Povinné při limitech</td></tr></tbody></table><p>Account ID najdete v informačním panelu účtu v Cloudflare Dashboard. Vyplňte ho jen tehdy, pokud má ImgBed dotazovat a vynucovat využití kvóty R2.</p><p><img src="'+a+'" alt="Získání Account ID" loading="lazy"></p><h2 id="postup-nastaveni" tabindex="-1">Postup nastavení <a class="header-anchor" href="#postup-nastaveni" aria-label="Permalink to &quot;Postup nastavení&quot;">​</a></h2><ol><li>Vytvořte R2 bucket v Cloudflare.</li><li>Otevřete nastavení Cloudflare pro projekt ImgBed.</li><li>Přidejte R2 bucket binding.</li><li>Nastavte <code>Variable name</code> na <code>img_r2</code>.</li><li>Vyberte vytvořený R2 bucket.</li><li>Uložte binding a znovu nasaďte ImgBed.</li><li>Vraťte se do ImgBed -&gt; Nastavení systému -&gt; Nastavení nahrávání.</li><li>Ověřte, že se kanál <code>Cloudflare R2</code> zobrazuje a je povolený.</li></ol><p>Pokud chcete, aby se R2 vybíral podle kapacity, zapněte limit kapacity a před uložením vyplňte Account ID, název bucketu, limit a prahovou hodnotu.</p><p><img src="'+o+'" alt="Nastavení limitů kapacity" loading="lazy"></p><h2 id="overeni" tabindex="-1">Ověření <a class="header-anchor" href="#overeni" aria-label="Permalink to &quot;Ověření&quot;">​</a></h2><ul><li>Pevný kanál <code>Cloudflare R2</code> se zobrazuje v Nastavení nahrávání.</li><li>Karta kanálu ukazuje, že je kanál povolený.</li><li>Malý testovací soubor se nahraje úspěšně a vrácený odkaz se normálně otevře.</li><li>Pokud se při otevření souboru zobrazí <code>R2 database binding is not configured</code>, runtime nedostal binding <code>img_r2</code>. Zkontrolujte název bindingu v Cloudflare a projekt znovu nasaďte.</li></ul>',37)])])}const g=d(r,[["render",u]]);export{m as __pageData,g as default};
